      {
        "step_order": 1,
        "action_type": "view-change",
        "direction": "low-angle",
        "guide_text": "将相机降低，更接近地面上的蔬菜，捕捉低角度视点。"
      },
      {
        "step_order": 2,
        "action_type": "shift",
        "direction": "left",
        "guide_text": "向左移动相机，使水泥基座的边缘（作为一条引导线）从画面的右下角延伸出来。"
      },
      {
        "step_order": 3,
        "action_type": "zoom",
        "direction": "in",
